generators.postProcess:
function (e) {
    return e.startsWith("fatal:") ? [] : e.split("\n").filter(t => t.indexOf("::") > 0).map(t => ({
      name: t.substring(t.indexOf("::") + 2, t.length),
      icon: "fig://icon?type=php",
      description: t.substring(t.indexOf("::") + 2, t.length)
    }));
  }
